import { useSupabaseAuth, supabase } from "./useSupabase";
import { useEffect } from "react";
import React, { useState, useRef, useContext, createContext, useMemo } from "react";
import {
  Home, Search, Bell, User, MessageCircle, Bookmark, Send, X, BadgeCheck, ChevronLeft,
  Play, ChevronRight, Trophy, Image as ImageIcon, Video, BarChart2, Mic, MicOff, PhoneOff,
  Plus, Camera, Pencil, Check, Lock, LogOut, UserPlus, Eye, EyeOff, AlertCircle, Trash2,
  Sparkles, Mail, CreditCard, Star,
} from "lucide-react";

const LOGO_URI = "data:image/png;base64,";

/* ---------------------------------------------------------
   NTL48 — fan-club app.
   Brand palette pulled from the logo (deep teal → soft green),
   real accounts only (login/register), no seeded fake members.
--------------------------------------------------------- */


const PRIMARY = "#2F8F6C";        // main brand green (from logo)
const PRIMARY_DARK = "#173F3A";   // deep teal (from logo shadow tones)
const PRIMARY_SOFT = "#5FB58C";   // lighter mint accent
const PRIMARY_TINT = "#2F8F6C1A"; // translucent tint for backgrounds
const DANGER = "#E0554F";

const GREEN_PALETTE = ["#2F8F6C", "#3FA37E", "#1C5C52", "#5FB58C", "#276C5E", "#4E9B7D"];
function stringToColor(str) {
  if (!str) return "#8B8894";
  let hash = 0;
  for (let i = 0; i < str.length; i++) hash = str.charCodeAt(i) + ((hash << 5) - hash);
  return GREEN_PALETTE[Math.abs(hash) % GREEN_PALETTE.length];
}
const unitColor = (unit) => stringToColor(unit);
const unitLabel = (unit) => (unit && unit.trim() ? unit.trim() : "Member");
const initialsOf = (name) => (name || "?").trim().slice(0, 2).toUpperCase();

const fmt = (n) => (n >= 1000 ? (n / 1000).toFixed(1).replace(/\.0$/, "") + "K" : String(n || 0));

let _uidN = 0;
const uid = (p = "id") => `${p}-${Date.now().toString(36)}-${(_uidN++)}-${Math.random().toString(36).slice(2, 7)}`;

function fileToDataURL(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* ---------- Global app context (replaces prop-drilling + fixes state loss on navigation) ---------- */
const AppCtx = createContext(null);
const useCtx = () => useContext(AppCtx);

/* ---------- Cheer / light-stick icon (used for Like + Live buttons) ---------- */
function Penlight({ active, color = PRIMARY, size = 24 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      style={{ filter: active ? `drop-shadow(0 0 5px ${color})` : "none", transition: "filter 200ms ease" }}>
      <rect x="10" y="11" width="4" height="10" rx="1.5" fill={active ? color : "#c9c6d6"} />
      <path d="M12 2c-2.2 2-3.2 4.4-3.2 6.2A3.2 3.2 0 0 0 12 11.4a3.2 3.2 0 0 0 3.2-3.2C15.2 6.4 14.2 4 12 2z"
        fill={active ? color : "#b9b6c6"} style={{ transition: "fill 200ms ease" }} />
    </svg>
  );
}

/* ---------- Avatar (idol accounts get the verified ring + badge) ---------- */
function Avatar({ user, size = 44, ring }) {
  const color = unitColor(user.unit);
  return (
    <div style={{ width: size, height: size, borderRadius: "50%", padding: ring ? 2.5 : 0, background: ring ? `linear-gradient(135deg, ${color}, ${PRIMARY_SOFT})` : "transparent", position: "relative" }}>
      <div style={{ width: "100%", height: "100%", borderRadius: "50%", overflow: "hidden", background: `linear-gradient(135deg, ${color}, ${color}99)`, display: "flex", alignItems: "center", justifyContent: "center", border: "2px solid #FAF8F5" }}>
        {user.avatar ? (
          <img src={user.avatar} alt={user.displayName} className="w-full h-full object-cover" />
        ) : (
          <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 600, fontSize: size * 0.32, color: "#fff" }}>{initialsOf(user.displayName)}</span>
        )}
      </div>
      {user.role === "member" && (
        <BadgeCheck size={size * 0.32} color="#fff" fill="#3B9EFF" style={{ position: "absolute", bottom: -1, right: -1, background: "#FAF8F5", borderRadius: "50%" }} />
      )}
    </div>
  );
}

function UnitTag({ unit, small }) {
  const color = unitColor(unit);
  return (
    <span className={`inline-flex items-center rounded-full font-semibold ${small ? "px-2 py-0.5 text-[10px]" : "px-2.5 py-1 text-xs"}`} style={{ background: `${color}20`, color, fontFamily: "Prompt, sans-serif" }}>
      {unitLabel(unit)}
    </span>
  );
}

function NameWithBadge({ name, verified, size = 14 }) {
  return (
    <span className="inline-flex items-center gap-1">
      <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 600, fontSize: size, color: "#1A1A1E" }}>{name}</span>
      {verified && <BadgeCheck size={size - 1} color="#fff" fill="#3B9EFF" />}
    </span>
  );
}

/* ---------- Reusable auth-form inputs ---------- */
function FieldInput({ icon: Icon, ...props }) {
  return (
    <div className="flex items-center gap-2 rounded-xl px-3 py-2.5" style={{ background: "#F3F0EA" }}>
      {Icon && <Icon size={16} color="#8B8894" />}
      <input {...props} className="flex-1 bg-transparent text-sm outline-none" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
    </div>
  );
}
function PasswordField({ value, onChange, placeholder }) {
  const [show, setShow] = useState(false);
  return (
    <div className="flex items-center gap-2 rounded-xl px-3 py-2.5" style={{ background: "#F3F0EA" }}>
      <Lock size={16} color="#8B8894" />
      <input type={show ? "text" : "password"} value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
        className="flex-1 bg-transparent text-sm outline-none" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
      <button type="button" onClick={() => setShow((s) => !s)} style={{ color: "#8B8894" }}>{show ? <EyeOff size={16} /> : <Eye size={16} />}</button>
    </div>
  );
}

/* ---------- Login / Register / Forgot Password ---------- */
function LoginForm({ onSwitch, onForgot }) {
  const { supabaseLogin } = useCtx();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    if (!email || !password) {
      setError("กรุณาใส่อีเมลและรหัสผ่าน");
      return;
    }
    try {
      setError("");
      setLoading(true);
      await supabaseLogin(email, password);
      // Supabase จะ auto update currentUser ใน App
    } catch (err) {
      // แสดง error message ที่แท้จริงจากระบบ
      setError(err.message || "ไม่สามารถเข้าสู่ระบบได้");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={submit} className="w-full max-w-xs flex flex-col gap-3">
      <FieldInput icon={Mail} type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" autoFocus disabled={loading} />
      <PasswordField value={password} onChange={setPassword} placeholder="Password" disabled={loading} />
      <button type="button" onClick={onForgot} className="self-end -mt-1 text-xs font-medium" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>
        Forgot password?
      </button>
      {error && <p className="text-xs flex items-center gap-1" style={{ color: DANGER, fontFamily: "Prompt, sans-serif" }}><AlertCircle size={13} />{error}</p>}
      <button type="submit" disabled={loading} className="w-full py-2.5 rounded-xl text-sm font-semibold" style={{ background: PRIMARY, color: "#fff", fontFamily: "Prompt, sans-serif", opacity: loading ? 0.6 : 1 }}>
        {loading ? (
          <span className="flex items-center justify-center gap-2">
            <span className="inline-block w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></span>
            กำลังเข้าสู่ระบบ...
          </span>
        ) : (
          "Login"
        )}
      </button>
      <p className="text-xs text-center" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>
        ยังไม่ได้เป็นสมาชิกใช่ไหม?{" "}
        <button type="button" onClick={onSwitch} className="font-semibold" style={{ color: PRIMARY }}>Register here</button>
      </p>
    </form>
  );
}

function RegisterForm({ onSwitch }) {
  const { supabaseRegister } = useCtx();
  
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [memberId, setMemberId] = useState("");
  const [memberName, setMemberName] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    if (!email.trim() || !password) { setError("กรุณากรอกอีเมลและรหัสผ่าน"); return; }
    if (password.length < 4) { setError("รหัสผ่านควรมีอย่างน้อย 4 ตัวอักษร"); return; }
    if (password !== confirm) { setError("รหัสผ่านยืนยันไม่ตรงกัน"); return; }
    if (!memberId.trim()) { setError("กรุณากรอก Member ID"); return; }
    
    try {
      setError("");
      setLoading(true);
      await supabaseRegister(email, password, memberId, memberName);
      onSwitch();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={submit} className="w-full max-w-xs flex flex-col gap-3">
      <h1 className="text-lg font-bold text-center mb-1" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>Register</h1>

      <FieldInput icon={Mail} type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" disabled={loading} />
      <PasswordField value={password} onChange={setPassword} placeholder="Password" disabled={loading} />
      <PasswordField value={confirm} onChange={setConfirm} placeholder="Confirm Password" disabled={loading} />

      <h2 className="text-sm font-bold mt-1" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>Member ID</h2>
      <FieldInput icon={CreditCard} value={memberId} onChange={(e) => setMemberId(e.target.value)} placeholder="Member ID" disabled={loading} />
      <p className="text-[11px] -mt-2" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>สำหรับ id ผู้ใช้งาน สามารถแก้ไขได้ทุก 14 วัน</p>

      <FieldInput icon={Pencil} value={memberName} onChange={(e) => setMemberName(e.target.value)} placeholder="Member Name" disabled={loading} />
      <p className="text-[11px] -mt-2" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>ชื่อสำหรับแสดงในแอป สามารถแก้ไขได้ตลอดเวลา</p>

      {error && <p className="text-xs flex items-center gap-1" style={{ color: DANGER, fontFamily: "Prompt, sans-serif" }}><AlertCircle size={13} />{error}</p>}

      <button type="submit" disabled={loading} className="w-full py-2.5 rounded-xl text-sm font-semibold flex items-center justify-center gap-1.5" style={{ background: PRIMARY, color: "#fff", fontFamily: "Prompt, sans-serif", opacity: loading ? 0.6 : 1 }}>
        <UserPlus size={16} /> {loading ? "กำลังสมัคร..." : "Register"}
      </button>
      <p className="text-xs text-center" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>
        มีบัญชีอยู่แล้ว?{" "}
        <button type="button" onClick={onSwitch} className="font-semibold" style={{ color: PRIMARY }}>เข้าสู่ระบบ</button>
      </p>
    </form>
  );
}

function ForgotPasswordForm({ onBack }) {
  const { users } = useCtx();
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState(null); // null | "sent" | "error"

  const submit = (e) => {
    e.preventDefault();
    const found = users.some((u) => u.email.toLowerCase() === email.trim().toLowerCase());
    setStatus(found ? "sent" : "error");
  };

  return (
    <form onSubmit={submit} className="w-full max-w-xs flex flex-col gap-3">
      <h1 className="text-lg font-bold text-center mb-1" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>Forgot Password</h1>
      <p className="text-xs text-center -mt-1.5 mb-1" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>Please enter your registered email</p>
      <FieldInput icon={Mail} type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" autoFocus />
      {status === "sent" && (
        <p className="text-xs flex items-center gap-1" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>
          <Check size={13} /> ส่งลิงก์รีเซ็ตรหัสผ่านไปยังอีเมลของคุณแล้ว (จำลอง)
        </p>
      )}
      {status === "error" && (
        <p className="text-xs flex items-center gap-1" style={{ color: DANGER, fontFamily: "Prompt, sans-serif" }}>
          <AlertCircle size={13} /> ไม่พบอีเมลนี้ในระบบ
        </p>
      )}
      <button type="submit" className="w-full py-2.5 rounded-xl text-sm font-semibold" style={{ background: PRIMARY, color: "#fff", fontFamily: "Prompt, sans-serif" }}>Reset password</button>
      <button type="button" onClick={onBack} className="text-xs font-semibold text-center flex items-center justify-center gap-1" style={{ color: "#8B8894", fontFamily: "Prompt, sans-serif" }}>
        <ChevronLeft size={13} /> กลับไปเข้าสู่ระบบ
      </button>
    </form>
  );
}

function AuthScreen() {
  const [mode, setMode] = useState("login"); // login | register | forgot
  return (
    <div className="w-full min-h-screen flex justify-center" style={{ background: "#EDEAE3" }}>
      <div className="w-full max-w-md flex flex-col items-center justify-center px-6 py-10" style={{ background: "#FAF8F5", minHeight: "100vh" }}>
        <img src={LOGO_URI} alt="NTL48" style={{ height: 64, width: "auto", objectFit: "contain", marginBottom: 28 }} />
        {mode === "login" && <LoginForm onSwitch={() => setMode("register")} onForgot={() => setMode("forgot")} />}
        {mode === "register" && <RegisterForm onSwitch={() => setMode("login")} />}
        {mode === "forgot" && <ForgotPasswordForm onBack={() => setMode("login")} />}
        <p className="text-[11px] text-center mt-8 max-w-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif", lineHeight: 1.5 }}>
          นี่คือโปรแกรมจำลองเพื่อความบันเทิงเท่านั้น ใช้สำหรับเป็นพื้นที่ชุมชนของ Northernlight48
        </p>
      </div>
    </div>
  );
}

/* ---------- Story bar + modal ---------- */
function StoryBar({ onOpen }) {
  const { stories, currentUser, users, addStory } = useCtx();
  const fileRef = useRef(null);
  const canPost = true; // privileges merged for now (no fan/member split at registration) — everyone can post stories

  const handleFile = async (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    const dataUrl = await fileToDataURL(file);
    addStory({ id: uid("story"), authorId: currentUser.id, image: dataUrl, createdAt: Date.now() });
    e.target.value = "";
  };

  if (!canPost && stories.length === 0) return null;

  return (
    <div className="flex gap-4 px-4 py-3 overflow-x-auto" style={{ scrollbarWidth: "none" }}>
      {canPost && (
        <button onClick={() => fileRef.current && fileRef.current.click()} className="flex flex-col items-center gap-1 flex-shrink-0" style={{ width: 68 }}>
          <div className="rounded-full flex items-center justify-center" style={{ width: 58, height: 58, background: "#F3F0EA", border: `1.5px dashed ${PRIMARY}` }}>
            <Plus size={22} color={PRIMARY} />
          </div>
          <span className="text-[11px] truncate w-full text-center" style={{ color: "#6B6874", fontFamily: "Prompt, sans-serif" }}>เพิ่มสตอรี่</span>
          <input ref={fileRef} type="file" accept="image/*" className="hidden" onChange={handleFile} />
        </button>
      )}
      {[...stories].reverse().map((s) => {
        const author = users.find((u) => u.id === s.authorId);
        if (!author) return null;
        return (
          <button key={s.id} onClick={() => onOpen(s)} className="flex flex-col items-center gap-1 flex-shrink-0" style={{ width: 68 }}>
            <Avatar user={author} size={58} ring />
            <span className="text-[11px] truncate w-full text-center" style={{ color: "#6B6874", fontFamily: "Prompt, sans-serif" }}>{author.displayName}</span>
          </button>
        );
      })}
    </div>
  );
}

function StoryModal({ story, onClose }) {
  const { users } = useCtx();
  if (!story) return null;
  const author = users.find((u) => u.id === story.authorId);
  if (!author) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center" style={{ background: "rgba(20,18,24,0.88)" }} onClick={onClose}>
      <div className="w-full max-w-sm mx-4" onClick={(e) => e.stopPropagation()}>
        <div className="h-0.5 rounded-full mb-3" style={{ background: unitColor(author.unit) }} />
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <Avatar user={author} size={34} />
            <div>
              <NameWithBadge name={author.displayName} verified={author.role === "member"} size={13} />
            </div>
          </div>
          <button onClick={onClose} className="text-white"><X size={22} /></button>
        </div>
        <div className="relative rounded-2xl overflow-hidden" style={{ aspectRatio: "9/16", background: "#111" }}>
          <img src={story.image} alt="" className="w-full h-full object-cover" />
        </div>
      </div>
    </div>
  );
}

/* ---------- Multi-image slider ---------- */
function ImageSlider({ images, type }) {
  const [idx, setIdx] = useState(0);
  const startX = useRef(null);
  const handleTouchStart = (e) => { startX.current = e.touches[0].clientX; };
  const handleTouchEnd = (e) => {
    if (startX.current === null) return;
    const dx = e.changedTouches[0].clientX - startX.current;
    if (dx < -40 && idx < images.length - 1) setIdx(idx + 1);
    if (dx > 40 && idx > 0) setIdx(idx - 1);
    startX.current = null;
  };
  return (
    <div className="relative w-full overflow-hidden" style={{ aspectRatio: "4/5", background: "#F3F0EA" }}
      onTouchStart={handleTouchStart} onTouchEnd={handleTouchEnd}>
      <div className="flex h-full transition-transform duration-300" style={{ transform: `translateX(-${idx * 100}%)`, width: `${images.length * 100}%` }}>
        {images.map((src, i) => (
          <div key={i} className="relative flex-shrink-0" style={{ width: `${100 / images.length}%`, height: "100%" }}>
            {type === "video" ? (
              <video src={src} className="w-full h-full object-cover" controls />
            ) : (
              <img src={src} alt="" className="w-full h-full object-cover" />
            )}
          </div>
        ))}
      </div>
      {images.length > 1 && (
        <>
          <div className="absolute top-3 right-3 px-2 py-0.5 rounded-full text-[11px] font-semibold" style={{ background: "rgba(0,0,0,0.45)", color: "#fff" }}>{idx + 1}/{images.length}</div>
          <div className="absolute bottom-3 left-0 right-0 flex justify-center gap-1">
            {images.map((_, i) => (
              <div key={i} onClick={() => setIdx(i)} className="rounded-full cursor-pointer transition-all"
                style={{ width: i === idx ? 16 : 6, height: 6, background: i === idx ? "#fff" : "rgba(255,255,255,0.5)" }} />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

/* ---------- Poll card ---------- */
function PollCard({ poll }) {
  const [voted, setVoted] = useState(null);
  const total = poll.options.reduce((s, o) => s + o.votes + (voted === o.label ? 1 : 0), 0);
  return (
    <div className="mx-4 mb-1 rounded-2xl p-4" style={{ background: "#F3F0EA" }}>
      <p className="text-[14px] font-semibold mb-3" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>{poll.question}</p>
      {poll.options.map((opt) => {
        const v = opt.votes + (voted === opt.label ? 1 : 0);
        const pct = total > 0 ? Math.round((v / total) * 100) : 0;
        const isVoted = voted === opt.label;
        return (
          <button key={opt.label} onClick={() => !voted && setVoted(opt.label)}
            className="w-full mb-2 rounded-xl overflow-hidden relative text-left"
            style={{ height: 40, background: "#FAF8F5", border: isVoted ? `1.5px solid ${PRIMARY}` : "1.5px solid #ECE8E1" }}>
            {voted && <div className="absolute inset-y-0 left-0 rounded-xl transition-all" style={{ width: `${pct}%`, background: isVoted ? PRIMARY_TINT : "#ECE8E1" }} />}
            <div className="absolute inset-0 flex items-center justify-between px-3">
              <span className="text-[13px] font-medium" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>{opt.label}</span>
              {voted && <span className="text-[12px] font-semibold" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>{pct}%</span>}
            </div>
          </button>
        );
      })}
      {voted && <p className="text-[11px] text-center mt-1" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>{total} โหวต</p>}
    </div>
  );
}

/* ---------- Post card ---------- */
function PostCard({ post }) {
  const { users, currentUser, likes, saved, openComments, drafts, toggleLike, toggleSave, toggleComments, setDraft, submitComment } = useCtx();
  const author = users.find((u) => u.id === post.authorId);
  if (!author) return null;
  const color = unitColor(author.unit);
  const images = post.images || [];
  const liked = !!likes[post.id]?.liked;
  const likeCount = likes[post.id]?.count ?? post.likes ?? 0;
  const isSaved = !!saved[post.id];
  const showComments = !!openComments[post.id];
  const draft = drafts[post.id] || "";

  return (
    <div className="border-b" style={{ borderColor: "#ECE8E1" }}>
      <div className="flex items-center justify-between px-4 py-3">
        <div className="flex items-center gap-3">
          <Avatar user={author} size={40} ring={author.role === "member"} />
          <div>
            <NameWithBadge name={author.displayName} verified={author.role === "member"} />
            <div className="flex items-center gap-1.5 mt-0.5">
              {author.role === "member" && author.unit && <UnitTag unit={author.unit} small />}
              <span className="text-[10px]" style={{ color: "#A9A6B4" }}>{author.role === "fan" ? "Fanclub" : (author.gen || "Member")}</span>
            </div>
          </div>
        </div>
      </div>

      {post.type === "poll" ? (
        <PollCard poll={post.poll} />
      ) : images.length > 0 ? (
        <ImageSlider images={images} type={post.type} />
      ) : null}

      {post.caption && <p className="px-4 pt-2 pb-1 text-[15px] leading-relaxed" style={{ color: "#3A3842", fontFamily: "Prompt, sans-serif" }}>{post.caption}</p>}

      <div className="flex items-center gap-4 px-4 pt-2">
        <button onClick={() => toggleLike(post.id)} className="flex items-center gap-1.5 active:scale-90 transition-transform">
          <Penlight active={liked} color={color} size={22} />
          <span className="text-sm font-semibold" style={{ color: liked ? color : "#5B5866", fontFamily: "Prompt, sans-serif" }}>{fmt(likeCount)}</span>
        </button>
        <button onClick={() => toggleComments(post.id)} className="flex items-center gap-1.5" style={{ color: "#5B5866" }}>
          <MessageCircle size={22} />
          <span className="text-sm">{post.comments.length}</span>
        </button>
        <button className="flex items-center gap-1.5 ml-auto" style={{ color: "#5B5866" }}><Send size={20} /></button>
        <button onClick={() => toggleSave(post.id)} className="active:scale-90 transition-transform">
          <Bookmark size={21} color={isSaved ? color : "#5B5866"} fill={isSaved ? color : "none"} />
        </button>
      </div>

      {showComments && (
        <div className="px-4 pt-2 pb-1">
          {post.comments.map((c, i) => (
            <p key={i} className="text-[13px] mb-1" style={{ color: "#6B6874", fontFamily: "Prompt, sans-serif" }}>
              <span className="font-semibold mr-1" style={{ color: "#3A3842" }}>{c.author}</span>{c.text}
            </p>
          ))}
        </div>
      )}

      <div className="flex items-center gap-2 px-4 py-3">
        <input
          value={draft}
          onChange={(e) => setDraft(post.id, e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && draft.trim() && submitComment(post.id)}
          placeholder="พิมพ์ให้กำลังใจ..."
          className="flex-1 bg-transparent text-sm outline-none"
          style={{ color: "#3A3842", fontFamily: "Prompt, sans-serif" }}
        />
        {draft.trim() && <button onClick={() => submitComment(post.id)} className="text-sm font-semibold" style={{ color, fontFamily: "Prompt, sans-serif" }}>ส่ง</button>}
      </div>
    </div>
  );
}

/* ---------- Create Post Modal ---------- */
function CreatePostModal({ open, onClose, onGoLive }) {
  const { currentUser, addPost } = useCtx();
  const [type, setType] = useState("photo"); // photo | text | poll | live
  const [mediaKind, setMediaKind] = useState("image"); // image | video
  const [text, setText] = useState("");
  const [images, setImages] = useState([]); // dataURLs
  const [videoUrl, setVideoUrl] = useState(null);
  const [pollQ, setPollQ] = useState("");
  const [pollOpts, setPollOpts] = useState(["", ""]);
  const imgInputRef = useRef(null);
  const videoInputRef = useRef(null);

  const reset = () => { setType("photo"); setMediaKind("image"); setText(""); setImages([]); setVideoUrl(null); setPollQ(""); setPollOpts(["", ""]); };
  const handleClose = () => { reset(); onClose(); };

  const handleImages = async (e) => {
    const files = Array.from(e.target.files || []);
    const room = Math.max(0, 10 - images.length);
    const picked = files.slice(0, room);
    const urls = await Promise.all(picked.map(fileToDataURL));
    setImages((prev) => [...prev, ...urls].slice(0, 10));
    e.target.value = "";
  };
  const removeImage = (i) => setImages((prev) => prev.filter((_, idx) => idx !== i));
  const handleVideo = (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setVideoUrl(URL.createObjectURL(file));
    e.target.value = "";
  };

  const handleSubmit = () => {
    if (type === "live") { handleClose(); onGoLive && onGoLive(); return; }
    if (type === "poll" && (!pollQ.trim() || pollOpts.filter((o) => o.trim()).length < 2)) return;
    if (type === "photo" && mediaKind === "image" && !text.trim() && images.length === 0) return;
    if (type === "photo" && mediaKind === "video" && !text.trim() && !videoUrl) return;
    if (type === "text" && !text.trim()) return;

    const post = {
      id: uid("post"),
      authorId: currentUser.id,
      type: type === "poll" ? "poll" : type === "text" ? "text" : mediaKind,
      images: type === "photo" ? (mediaKind === "video" ? (videoUrl ? [videoUrl] : []) : images) : [],
      caption: text.trim(),
      likes: 0,
      comments: [],
      poll: type === "poll" ? {
        question: pollQ.trim(),
        options: pollOpts.filter((o) => o.trim()).map((o) => ({ label: o.trim(), votes: 0 })),
      } : null,
      createdAt: Date.now(),
    };
    addPost(post);
    handleClose();
  };

  if (!open) return null;
  return (
    <div className="fixed inset-0 z-50 flex flex-col justify-end" style={{ background: "rgba(20,18,24,0.6)" }} onClick={handleClose}>
      <div className="w-full max-w-md mx-auto rounded-t-3xl overflow-hidden" style={{ background: "#FAF8F5", maxHeight: "88vh" }} onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between px-4 py-4" style={{ borderBottom: "1px solid #ECE8E1" }}>
          <button onClick={handleClose} style={{ color: "#5B5866" }}><X size={20} /></button>
          <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 15, color: "#1A1A1E" }}>สร้างโพสต์ใหม่</span>
          <button onClick={handleSubmit} className="px-4 py-1.5 rounded-full text-sm font-semibold" style={{ background: PRIMARY, color: "#fff", fontFamily: "Prompt, sans-serif" }}>{type === "live" ? "เริ่มไลฟ์" : "โพสต์"}</button>
        </div>
        <div className="overflow-y-auto px-4 py-4" style={{ maxHeight: "75vh" }}>
          {/* ประเภทโพสต์ */}
          <div className="flex gap-2 mb-4">
            {[{ id: "photo", icon: ImageIcon, label: "รูปภาพ" }, { id: "text", icon: MessageCircle, label: "ข้อความ" }, { id: "poll", icon: BarChart2, label: "โหวต" }, { id: "live", icon: null, label: "ไลฟ์" }].map((t) => (
              <button key={t.id} onClick={() => setType(t.id)} className="flex-1 flex flex-col items-center gap-1 py-3 rounded-xl" style={{ background: type === t.id ? PRIMARY_TINT : "#F3F0EA", border: type === t.id ? `1.5px solid ${PRIMARY}` : "1.5px solid transparent" }}>
                {t.icon ? <t.icon size={18} color={type === t.id ? PRIMARY : "#8B8894"} /> : <Penlight active={type === t.id} color={PRIMARY} size={18} />}
                <span className="text-[11px] font-medium" style={{ color: type === t.id ? PRIMARY : "#8B8894", fontFamily: "Prompt, sans-serif" }}>{t.label}</span>
              </button>
            ))}
          </div>

          {type === "live" && (
            <div className="mb-3 rounded-2xl p-5 flex flex-col items-center text-center gap-2" style={{ background: `linear-gradient(120deg, ${PRIMARY_DARK}, #0F2622)` }}>
              <div className="rounded-full flex items-center justify-center" style={{ width: 48, height: 48, background: `${PRIMARY}33`, border: `1.5px solid ${PRIMARY}` }}>
                <Penlight active color={PRIMARY_SOFT} size={24} />
              </div>
              <p className="text-sm font-semibold" style={{ color: "#fff", fontFamily: "Prompt, sans-serif" }}>Start live with Fanclub</p>
              <p className="text-xs" style={{ color: "#B9D9CC", fontFamily: "Prompt, sans-serif" }}>กดโพสต์เพื่อเข้าห้องไลฟ์ทันที</p>
            </div>
          )}

          {(type === "photo" || type === "text") && (
            <textarea value={text} onChange={(e) => setText(e.target.value)} placeholder="เขียนคำบรรยาย..." rows={type === "text" ? 5 : 3}
              className="w-full rounded-xl px-3 py-2.5 text-sm outline-none resize-none mb-3"
              style={{ background: "#F3F0EA", color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
          )}

          {type === "photo" && (
            <div className="mb-3">
              <div className="flex gap-2 mb-3">
                {[{ id: "image", icon: ImageIcon, label: "รูปภาพ" }, { id: "video", icon: Video, label: "คลิป" }].map((mk) => (
                  <button key={mk.id} onClick={() => { setMediaKind(mk.id); setImages([]); setVideoUrl(null); }} className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold" style={{ background: mediaKind === mk.id ? "#1A1A1E" : "#F3F0EA", color: mediaKind === mk.id ? "#fff" : "#5B5866", fontFamily: "Prompt, sans-serif" }}>
                    <mk.icon size={13} /> {mk.label}
                  </button>
                ))}
              </div>

              {mediaKind === "image" ? (
                <>
                  <p className="text-[12px] font-semibold mb-2" style={{ color: "#8B8894", fontFamily: "Prompt, sans-serif" }}>อัปโหลดรูปภาพ (สูงสุด 10 รูป) · {images.length}/10</p>
                  <div className="grid grid-cols-3 gap-1.5 mb-2">
                    {images.map((src, i) => (
                      <div key={i} className="relative rounded-xl overflow-hidden" style={{ aspectRatio: "1" }}>
                        <img src={src} alt="" className="w-full h-full object-cover" />
                        <button onClick={() => removeImage(i)} className="absolute top-1 right-1 rounded-full p-1" style={{ background: "rgba(0,0,0,0.55)" }}>
                          <Trash2 size={12} color="#fff" />
                        </button>
                      </div>
                    ))}
                    {images.length < 10 && (
                      <button onClick={() => imgInputRef.current && imgInputRef.current.click()} className="rounded-xl flex items-center justify-center" style={{ aspectRatio: "1", background: "#ECE8E1", border: `1.5px dashed ${PRIMARY}` }}>
                        <Plus size={20} color={PRIMARY} />
                      </button>
                    )}
                  </div>
                  <input ref={imgInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleImages} />
                </>
              ) : (
                <>
                  <p className="text-[12px] font-semibold mb-2" style={{ color: "#8B8894", fontFamily: "Prompt, sans-serif" }}>อัปโหลดคลิปวิดีโอ</p>
                  {videoUrl ? (
                    <div className="relative rounded-xl overflow-hidden mb-2" style={{ aspectRatio: "4/5", background: "#000" }}>
                      <video src={videoUrl} className="w-full h-full object-cover" controls />
                      <button onClick={() => setVideoUrl(null)} className="absolute top-1.5 right-1.5 rounded-full p-1" style={{ background: "rgba(0,0,0,0.55)" }}>
                        <Trash2 size={13} color="#fff" />
                      </button>
                    </div>
                  ) : (
                    <button onClick={() => videoInputRef.current && videoInputRef.current.click()} className="w-full rounded-xl flex flex-col items-center justify-center gap-1.5 py-6" style={{ background: "#ECE8E1", border: `1.5px dashed ${PRIMARY}` }}>
                      <Video size={22} color={PRIMARY} />
                      <span className="text-xs font-medium" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>เลือกไฟล์วิดีโอ</span>
                    </button>
                  )}
                  <input ref={videoInputRef} type="file" accept="video/*" className="hidden" onChange={handleVideo} />
                </>
              )}
            </div>
          )}

          {type === "poll" && (
            <div>
              <textarea value={pollQ} onChange={(e) => setPollQ(e.target.value)} placeholder="คำถาม..." rows={2}
                className="w-full rounded-xl px-3 py-2.5 text-sm outline-none resize-none mb-3"
                style={{ background: "#F3F0EA", color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
              {pollOpts.map((opt, i) => (
                <div key={i} className="flex items-center gap-2 mb-2">
                  <input value={opt} onChange={(e) => { const a = [...pollOpts]; a[i] = e.target.value; setPollOpts(a); }}
                    placeholder={`ตัวเลือก ${i + 1}`}
                    className="flex-1 rounded-xl px-3 py-2 text-sm outline-none"
                    style={{ background: "#F3F0EA", color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
                  {pollOpts.length > 2 && <button onClick={() => setPollOpts(pollOpts.filter((_, j) => j !== i))} style={{ color: "#A9A6B4" }}><X size={16} /></button>}
                </div>
              ))}
              {pollOpts.length < 6 && (
                <button onClick={() => setPollOpts([...pollOpts, ""])} className="flex items-center gap-1.5 text-sm font-semibold" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>
                  <Plus size={15} /> เพิ่มตัวเลือก
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ---------- Live Stage ---------- */
function LiveStageModal({ open, onClose }) {
  const { currentUser } = useCtx();
  const [muted, setMuted] = useState(false);
  const [reacted, setReacted] = useState(null);
  if (!open) return null;
  const hostColor = unitColor(currentUser.unit);
  return (
    <div className="fixed inset-0 z-50 flex flex-col" style={{ background: "#0F0E14" }}>
      <div className="flex items-center justify-between px-4 pt-5 pb-3">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full" style={{ background: "#FF4545" }} />
          <span className="text-xs font-bold" style={{ color: "#fff", fontFamily: "Prompt, sans-serif" }}>LIVE</span>
          <span className="text-xs ml-1" style={{ color: "#9B9BAA", fontFamily: "Prompt, sans-serif" }}>คุณกำลังไลฟ์อยู่</span>
        </div>
        <button onClick={onClose} className="rounded-full p-1.5" style={{ background: "rgba(255,255,255,0.12)" }}><X size={18} color="#fff" /></button>
      </div>

      <div className="px-4 pt-4 pb-2">
        <p className="text-[11px] font-semibold mb-3" style={{ color: "#9B9BAA", fontFamily: "Prompt, sans-serif", textTransform: "uppercase", letterSpacing: "0.06em" }}>บนเวที</p>
        <div className="flex gap-4 flex-wrap">
          <div className="flex flex-col items-center gap-2">
            <div className="relative">
              <div className="rounded-full flex items-center justify-center" style={{ width: 72, height: 72, background: `linear-gradient(135deg, ${hostColor}, ${hostColor}88)`, boxShadow: muted ? "none" : `0 0 0 3px ${hostColor}` }}>
                <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 22, color: "#fff" }}>{initialsOf(currentUser.displayName)}</span>
              </div>
              <div className="absolute -bottom-1 -right-1 rounded-full flex items-center justify-center" style={{ width: 22, height: 22, background: muted ? "#444" : hostColor }}>
                {muted ? <MicOff size={11} color="#fff" /> : <Mic size={11} color="#fff" />}
              </div>
            </div>
            <div className="text-center">
              <p className="text-[12px] font-semibold" style={{ color: "#fff", fontFamily: "Prompt, sans-serif" }}>{currentUser.displayName}</p>
              {currentUser.unit && <UnitTag unit={currentUser.unit} small />}
            </div>
          </div>
        </div>
      </div>

      <div className="mx-4 my-3 h-px" style={{ background: "rgba(255,255,255,0.08)" }} />

      <div className="px-4 flex-1 overflow-y-auto flex items-center justify-center">
        <p className="text-[12px]" style={{ color: "#9B9BAA", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีผู้ฟังเข้าร่วม</p>
      </div>

      <div className="px-4 py-3">
        <div className="flex gap-3 justify-center mb-4">
          {["❤️", "🔥", "👏", "⭐"].map((r) => (
            <button key={r} onClick={() => { setReacted(r); setTimeout(() => setReacted(null), 800); }}
              className="text-2xl rounded-full px-3 py-2 transition-transform active:scale-110"
              style={{ background: reacted === r ? "rgba(255,255,255,0.18)" : "rgba(255,255,255,0.08)" }}>
              {r}
            </button>
          ))}
        </div>
        <div className="flex items-center justify-center gap-6">
          <button onClick={() => setMuted(!muted)} className="rounded-full flex items-center justify-center" style={{ width: 52, height: 52, background: muted ? "#FF4545" : "rgba(255,255,255,0.14)" }}>
            {muted ? <MicOff size={22} color="#fff" /> : <Mic size={22} color="#fff" />}
          </button>
          <button onClick={onClose} className="rounded-full flex items-center justify-center" style={{ width: 52, height: 52, background: "#FF4545" }}>
            <PhoneOff size={22} color="#fff" />
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------- Cards / member gallery ---------- */
function CardsView() {
  const { members } = useCtx();
  return (
    <div className="px-4 py-5">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>เมมเบอร์ทั้งหมด</h2>
        <span className="text-xs px-3 py-1 rounded-full font-semibold" style={{ background: PRIMARY_TINT, color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>{members.length} คน</span>
      </div>
      {members.length === 0 ? (
        <div className="rounded-2xl p-8 text-center" style={{ background: "#F9F7F3" }}>
          <p className="text-sm font-semibold mb-1" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีเมมเบอร์ในระบบ</p>
          <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>เมื่อมีการสมัครบัญชีประเภทเมมเบอร์ จะแสดงที่นี่</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 gap-3">
          {members.map((m) => (
            <div key={m.id} className="rounded-2xl overflow-hidden relative flex items-center justify-center" style={{ aspectRatio: "3/4", background: `linear-gradient(145deg, ${unitColor(m.unit)}33, ${unitColor(m.unit)}99)` }}>
              {m.avatar ? <img src={m.avatar} alt={m.displayName} className="w-full h-full object-cover" /> : <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 30, color: "#fff" }}>{initialsOf(m.displayName)}</span>}
              <div className="absolute inset-0" style={{ background: "linear-gradient(to top, rgba(0,0,0,0.7) 30%, transparent 65%)" }} />
              <div className="absolute bottom-0 left-0 right-0 p-3">
                <p className="text-white font-bold text-sm" style={{ fontFamily: "Prompt, sans-serif" }}>{m.displayName}</p>
                <div className="flex items-center justify-between mt-1">
                  <UnitTag unit={m.unit} small />
                  {m.gen && <span className="text-[10px] font-semibold" style={{ color: "rgba(255,255,255,0.75)", fontFamily: "Prompt, sans-serif" }}>{m.gen}</span>}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ---------- Search / Explore view ---------- */
function SearchView({ query, setQuery, gen, setGen }) {
  const { members } = useCtx();
  const gens = useMemo(() => ["ALL", ...Array.from(new Set(members.map((m) => m.gen).filter(Boolean)))], [members]);
  const results = members.filter((m) => (gen === "ALL" || m.gen === gen) && m.displayName.toLowerCase().includes(query.toLowerCase()));
  return (
    <div className="pb-6">
      <div className="px-4 pt-4 pb-3">
        <div className="flex items-center gap-2 rounded-xl px-3 py-2.5" style={{ background: "#F3F0EA" }}>
          <Search size={18} color="#8B8894" />
          <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="ค้นหาเมมเบอร์ NTL48..." className="flex-1 bg-transparent text-sm outline-none" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }} />
        </div>
      </div>
      {gens.length > 1 && (
        <>
          <p className="px-4 text-[11px] font-semibold mb-1.5" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>รุ่น</p>
          <div className="flex gap-2 px-4 pb-4 overflow-x-auto">
            {gens.map((g) => {
              const active = gen === g;
              return (
                <button key={g} onClick={() => setGen(g)} className="px-3.5 py-1.5 rounded-full text-xs font-semibold flex-shrink-0" style={{ fontFamily: "Prompt, sans-serif", color: active ? "#fff" : "#5B5866", background: active ? "#1A1A1E" : "#F3F0EA" }}>
                  {g === "ALL" ? "ทั้งหมด" : g}
                </button>
              );
            })}
          </div>
        </>
      )}
      <div className="grid grid-cols-3 gap-3 px-4">
        {results.map((m) => (
          <div key={m.id} className="flex flex-col items-center gap-2 rounded-xl py-4" style={{ background: "#F9F7F3" }}>
            <Avatar user={m} size={56} ring />
            <NameWithBadge name={m.displayName.split(" ")[0]} verified size={12} />
            {m.unit && <UnitTag unit={m.unit} small />}
          </div>
        ))}
        {results.length === 0 && <p className="col-span-3 text-center text-sm py-10" style={{ color: "#A9A6B4" }}>ไม่พบผลลัพธ์ ลองคำอื่นดูนะ</p>}
      </div>
    </div>
  );
}

/* ---------- Notifications (derived from real member posts) ---------- */
function NotificationsView() {
  const { posts, users } = useCtx();
  const memberPosts = posts.filter((p) => {
    const a = users.find((u) => u.id === p.authorId);
    return a && a.role === "member";
  }).slice(0, 20);
  return (
    <div className="px-4 py-4 flex flex-col gap-3">
      <h2 className="text-xl font-semibold mb-1" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>การแจ้งเตือน</h2>
      {memberPosts.length === 0 && (
        <p className="text-sm text-center py-10" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีการแจ้งเตือน</p>
      )}
      {memberPosts.map((n) => {
        const author = users.find((u) => u.id === n.authorId);
        return (
          <div key={n.id} className="rounded-xl p-3.5 flex items-center gap-3" style={{ background: "#F9F7F3", borderLeft: `3px solid ${unitColor(author.unit)}` }}>
            <Avatar user={author} size={40} />
            <div className="flex-1">
              <p className="text-[14px]" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>
                <NameWithBadge name={author.displayName} verified size={13} /> <span className="font-normal">ได้โพสต์อัปเดตใหม่</span>
              </p>
              {n.caption && <p className="text-[12px] mt-0.5 truncate" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>{n.caption}</p>}
            </div>
          </div>
        );
      })}
    </div>
  );
}

/* ---------- Profile view ---------- */
function ProfileView() {
  const { currentUser, updateCurrentUser, logout, posts } = useCtx();
  const [editingName, setEditingName] = useState(false);
  const [nameDraft, setNameDraft] = useState(currentUser.displayName);
  const [editingMemberId, setEditingMemberId] = useState(false);
  const [memberIdDraft, setMemberIdDraft] = useState(currentUser.memberId);
  const [uploading, setUploading] = useState(false); // ✅ เพิ่มนี้
  const [uploadError, setUploadError] = useState(null); // ✅ เพิ่มนี้
  const [savingName, setSavingName] = useState(false);           // ✅ NEW - Track name saving
  const [savingMemberId, setSavingMemberId] = useState(false);  // ✅ NEW - Track ID saving
  const coverInputRef = useRef(null);
  const avatarInputRef = useRef(null);

  const DAY_MS = 24 * 60 * 60 * 1000;
  const nextMemberIdEditAt = (currentUser.memberIdUpdatedAt || 0) + 14 * DAY_MS;
  const canEditMemberId = Date.now() >= nextMemberIdEditAt;
  const daysUntilMemberIdEdit = Math.max(0, Math.ceil((nextMemberIdEditAt - Date.now()) / DAY_MS));

  const { uploadProfileImage } = useCtx();

  const handleFile = (field) => async (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;

    setUploading(true);
    setUploadError(null);

    try {
      // 1️⃣ อัพโหลดไปเก็บใน Supabase Storage
      const publicUrl = await uploadProfileImage(file, currentUser.id, field);

      // 2️⃣ ให้ UI ดูค่าใหม่ทันที
      const fieldKey = field === 'avatar' ? 'avatar_url' : 'cover_url';
      updateCurrentUser({ [fieldKey]: publicUrl });

      // 3️⃣ บันทึก URL ลงฐานข้อมูล
      const { data, error } = await supabase
        .from("users")
        .update({ [fieldKey]: publicUrl })
        .eq("uid", currentUser.id)
        .select()
        .single();

      if (error) {
        console.error(`Error saving ${fieldKey}:`, error);
        setUploadError(`ไม่สามารถบันทึก${field === 'avatar' ? 'รูปโปรไฟล์' : 'ปก'}ได้: ${error.message}`);
        throw error;
      }

      console.log(`✅ บันทึก ${field} สำเร็จ`);
      if (data) {
        updateCurrentUser(data);
      }

    } catch (err) {
      console.error(`❌ Error saving ${field}:`, err);
      const fieldName = field === 'avatar' ? 'รูปโปรไฟล์' : 'ปก';
      setUploadError(`เกิดข้อผิดพลาด: ${err.message}`);
    } finally {
      setUploading(false);
      e.target.value = "";
    }
  };

  const saveName = async () => {
    const v = nameDraft.trim();
    if (!v) {
      setEditingName(false);
      return;
    }
    
    setSavingName(true);
    setUploadError(null);
    
    try {
      // ✅ Step 1: Save to Supabase database FIRST
      const { data, error } = await supabase
        .from("users")
        .update({ displayName: v })
        .eq("uid", currentUser.id)
        .select()
        .single();
      
      if (error) {
        console.error("❌ Error saving name:", error);
        setUploadError(`ไม่สามารถบันทึกชื่อได้: ${error.message}`);
        return;
      }
      
      console.log("✅ ชื่อถูกบันทึกเรียบร้อย");
      
      // ✅ Step 2: Update local state with database response
      if (data) {
        updateCurrentUser(data);
      }
      
      setEditingName(false);
    } catch (err) {
      console.error("❌ Error saving name:", err);
      setUploadError(`เกิดข้อผิดพลาด: ${err.message}`);
    } finally {
      setSavingName(false);
    }
  };

  const saveMemberId = async () => {
    const v = memberIdDraft.trim();
    
    if (!v) {
      setEditingMemberId(false);
      return;
    }
    
    if (!canEditMemberId) {
      console.warn("Cannot edit memberId - 14 day cooldown not passed");
      setEditingMemberId(false);
      return;
    }
    
    setSavingMemberId(true);
    setUploadError(null);
    
    try {
      const now = Date.now();
      
      // ✅ Step 1: Save to Supabase database FIRST
      const { data, error } = await supabase
        .from("users")
        .update({ 
          memberId: v, 
          memberIdUpdatedAt: now 
        })
        .eq("uid", currentUser.id)
        .select()
        .single();
      
      if (error) {
        console.error("❌ Error saving memberId:", error);
        setUploadError(`ไม่สามารถบันทึก ID ได้: ${error.message}`);
        return;
      }
      
      console.log("✅ ID ถูกบันทึกเรียบร้อย");
      
      // ✅ Step 2: Update local state with database response
      if (data) {
        updateCurrentUser(data);
      }
      
      setEditingMemberId(false);
    } catch (err) {
      console.error("❌ Error saving memberId:", err);
      setUploadError(`เกิดข้อผิดพลาด: ${err.message}`);
    } finally {
      setSavingMemberId(false);
    }
  };

  const myPosts = posts.filter((p) => p.authorId === currentUser.id);
  const likesReceived = myPosts.reduce((s, p) => s + (p.likes || 0), 0);
  const commentsReceived = myPosts.reduce((s, p) => s + p.comments.length, 0);

  return (
    <div className="pb-6">
      <div className="relative w-full" style={{ aspectRatio: "16/7", background: currentUser?.cover_url ? "#ECE8E1" : `linear-gradient(120deg, ${PRIMARY}, ${PRIMARY_SOFT})` }}>
        {currentUser?.cover_url && <img src={currentUser.cover_url} alt="cover" className="w-full h-full object-cover" onError={(e) => { e.target.style.display = "none"; }} />}
        <button 
          onClick={() => coverInputRef.current && coverInputRef.current.click()}
          disabled={uploading}
          className="absolute bottom-2.5 right-2.5 flex items-center gap-1.5 rounded-full px-2.5 py-1.5"
          style={{ 
            background: uploading ? "rgba(20,18,24,0.3)" : "rgba(20,18,24,0.55)",
            cursor: uploading ? "not-allowed" : "pointer",
            opacity: uploading ? 0.6 : 1
          }}
        >
          <Camera size={13} color="#fff" />
          <span className="text-[11px] font-medium" style={{ color: "#fff", fontFamily: "Prompt, sans-serif" }}>
            {uploading ? "กำลังอัปโหลด..." : "แก้ไขปก"}
          </span>
        </button>
        <input ref={coverInputRef} type="file" accept="image/*" className="hidden" onChange={handleFile("cover")} />
      </div>

      <div className="px-4">
        {/* Error Message */}
        {uploadError && (
          <div className="mb-3 p-3 rounded-lg bg-red-50 border border-red-200">
            <p className="text-sm text-red-600" style={{ fontFamily: "Prompt, sans-serif" }}>
              ⚠️ {uploadError}
            </p>
          </div>
        )}

        <div className="flex items-center justify-between">
          <div className="relative -mt-10 mb-3" style={{ width: 84 }}>
            <div className="rounded-full overflow-hidden flex items-center justify-center" style={{ width: 84, height: 84, border: "3px solid #FAF8F5", background: currentUser?.avatar_url ? "#ECE8E1" : `linear-gradient(135deg, ${PRIMARY}, ${PRIMARY_SOFT})` }}>
              {currentUser?.avatar_url ? <img src={currentUser.avatar_url} alt="avatar" className="w-full h-full object-cover" onError={(e) => { e.target.style.display = "none"; }} /> : <User size={32} color="#fff" />}
            </div>
            <button 
              onClick={() => avatarInputRef.current && avatarInputRef.current.click()}
              disabled={uploading}
              className="absolute bottom-0 right-0 rounded-full p-1.5 flex items-center justify-center"
              style={{ 
                background: PRIMARY, 
                border: "2px solid #FAF8F5",
                cursor: uploading ? "not-allowed" : "pointer",
                opacity: uploading ? 0.6 : 1
              }}
            >
              <Camera size={12} color="#fff" />
            </button>
            <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleFile("avatar")} />
          </div>
          <button onClick={logout} className="flex items-center gap-1.5 text-xs font-semibold mt-2" style={{ color: "#8B8894", fontFamily: "Prompt, sans-serif" }}>
            <LogOut size={14} /> ออกจากระบบ
          </button>
        </div>

        <div className="flex items-center gap-2 mb-1">
          {editingName ? (
            <>
              <input
                autoFocus
                disabled={savingName}
                value={nameDraft}
                onChange={(e) => setNameDraft(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && !savingName && saveName()}
                className="text-base font-bold rounded-lg px-2 py-1 outline-none"
                style={{ 
                  fontFamily: "Prompt, sans-serif", 
                  color: "#1A1A1E", 
                  background: "#F3F0EA", 
                  border: `1.5px solid ${PRIMARY}`,
                  opacity: savingName ? 0.6 : 1
                }}
              />
              <button 
                onClick={saveName} 
                disabled={savingName}
                className="rounded-full p-1.5" 
                style={{ 
                  background: PRIMARY,
                  opacity: savingName ? 0.6 : 1,
                  cursor: savingName ? "not-allowed" : "pointer"
                }}
              >
                <Check size={13} color="#fff" />
              </button>
            </>
          ) : (
            <>
              <p className="text-base font-bold" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>
                {currentUser?.displayName || currentUser?.memberName || currentUser?.email?.split("@")[0] || "ผู้ใช้"}
              </p>
              {currentUser?.role === "member" && <BadgeCheck size={15} color="#fff" fill="#3B9EFF" />}
              <button onClick={() => { setNameDraft(currentUser?.displayName || ""); setEditingName(true); }} style={{ color: "#A9A6B4" }}><Pencil size={13} /></button>
            </>
          )}
        </div>
        <div className="flex items-center gap-1.5 mb-4">
          {editingMemberId ? (
            <>
              <span className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>@</span>
              <input
                autoFocus
                disabled={savingMemberId}
                value={memberIdDraft}
                onChange={(e) => setMemberIdDraft(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && !savingMemberId && saveMemberId()}
                className="text-xs font-medium rounded-lg px-2 py-1 outline-none"
                style={{ 
                  fontFamily: "Prompt, sans-serif", 
                  color: "#1A1A1E", 
                  background: "#F3F0EA", 
                  border: `1.5px solid ${PRIMARY}`,
                  opacity: savingMemberId ? 0.6 : 1
                }}
              />
              <button 
                onClick={saveMemberId} 
                disabled={savingMemberId}
                className="rounded-full p-1" 
                style={{ 
                  background: PRIMARY,
                  opacity: savingMemberId ? 0.6 : 1,
                  cursor: savingMemberId ? "not-allowed" : "pointer"
                }}
              >
                <Check size={11} color="#fff" />
              </button>
            </>
          ) : (
            <>
              <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>
                @{currentUser?.memberId || "user"} · {currentUser?.role === "member" ? (unitLabel(currentUser?.unit || "")) : "Fanclub"}
              </p>
              <button
                onClick={() => { if (canEditMemberId) { setMemberIdDraft(currentUser?.memberId || ""); setEditingMemberId(true); } }}
                title={canEditMemberId ? "แก้ไข Member ID" : `แก้ไขได้อีกครั้งในอีก ${daysUntilMemberIdEdit} วัน`}
                style={{ 
                  color: canEditMemberId ? "#A9A6B4" : "#D8D5CE",
                  cursor: canEditMemberId ? "pointer" : "not-allowed",
                  opacity: canEditMemberId ? 1 : 0.5
                }}
              >
                <Pencil size={11} />
              </button>
            </>
          )}
        </div>

        <div className="flex items-center justify-around mb-4 py-3 px-4" style={{ borderTop: "1px solid #ECE8E1", borderBottom: "1px solid #ECE8E1" }}>
          {/* Oshi Member */}
          <div className="text-center flex-1">
            <p className="text-xl font-bold mb-0.5" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>0</p>
            <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>Oshi Member</p>
          </div>

          {/* Kami-Oshi */}
          <div className="text-center flex-1">
            <p className="text-xl font-bold mb-0.5" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>0</p>
            <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>Kami-Oshi</p>
          </div>

          {/* Stars */}
          <div className="text-center flex-1">
            <div className="flex items-center justify-center gap-0.5 mb-0.5">
              <Sparkles size={18} color={PRIMARY} />
              <p className="text-xl font-bold" style={{ fontFamily: "Prompt, sans-serif", color: "#1A1A1E" }}>0</p>
            </div>
            <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>Stars</p>
          </div>
        </div>

        <p className="text-xs uppercase tracking-wide mb-2" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>โพสต์ของฉัน</p>
        <div className="flex flex-col -mx-4">
          {myPosts.length === 0 && (
            <p className="text-xs py-6 text-center" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีโพสต์ — ลองสร้างโพสต์แรกของคุณดูสิ</p>
          )}
          {myPosts.map((p) => <PostCard key={p.id} post={p} />)}
        </div>
      </div>
    </div>
  );
}

/* ---------- Champ of the Week + Top 5 (based on real like counts) ---------- */
function useMemberScores() {
  const { members, posts, likes } = useCtx();
  return useMemo(() => {
    return members.map((m) => {
      const score = posts
        .filter((p) => p.authorId === m.id)
        .reduce((s, p) => s + (likes[p.id]?.count ?? p.likes ?? 0), 0);
      return { member: m, score };
    }).sort((a, b) => b.score - a.score);
  }, [members, posts, likes]);
}

function ChampHero() {
  const ranked = useMemberScores();
  if (ranked.length === 0) {
    return (
      <div className="px-4 pt-4">
        <div className="rounded-2xl p-5 text-center" style={{ background: "#F9F7F3" }}>
          <p className="text-sm font-semibold mb-1" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีเมมเบอร์ในระบบ</p>
          <p className="text-xs" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>อันดับประจำสัปดาห์จะแสดงเมื่อมีเมมเบอร์และโพสต์</p>
        </div>
      </div>
    );
  }
  const { member, score } = ranked[0];
  const color = unitColor(member.unit);
  return (
    <div className="px-4 pt-4">
      <div className="relative rounded-2xl overflow-hidden flex items-center gap-3 p-3" style={{ background: `linear-gradient(120deg, ${color}18, #F9F7F3)`, border: `1px solid ${color}30` }}>
        <div className="relative rounded-xl overflow-hidden flex-shrink-0 flex items-center justify-center" style={{ width: 84, height: 100, background: `linear-gradient(135deg, ${color}, ${color}99)` }}>
          {member.avatar ? <img src={member.avatar} alt={member.displayName} className="w-full h-full object-cover" /> : <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 24, color: "#fff" }}>{initialsOf(member.displayName)}</span>}
        </div>
        <div className="flex-1 min-w-0">
          <div className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full mb-1.5" style={{ background: "#FDF3DC" }}>
            <Trophy size={11} color="#D9A02A" fill="#F3C765" />
            <span className="text-[10px] font-semibold" style={{ color: "#8A6A1E", fontFamily: "Prompt, sans-serif" }}>Champ of the Week</span>
          </div>
          <div className="flex items-center gap-1 mb-1">
            <span className="truncate" style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 16, color: "#1A1A1E" }}>{member.displayName}</span>
            <BadgeCheck size={14} color="#fff" fill="#3B9EFF" className="flex-shrink-0" />
          </div>
          <span className="inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-semibold" style={{ background: `${color}20`, color, fontFamily: "Prompt, sans-serif" }}>
            {unitLabel(member.unit)}{member.gen ? ` · ${member.gen}` : ""}
          </span>
        </div>
        <div className="text-right flex-shrink-0 pr-1">
          <p className="text-[10px]" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>คะแนนสัปดาห์นี้</p>
          <p style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 18, color: "#1A1A1E" }}>{fmt(score)}</p>
        </div>
      </div>
    </div>
  );
}

function AllScoresModal({ open, onClose }) {
  const ranked = useMemberScores();
  if (!open) return null;
  return (
    <div className="fixed inset-0 z-50 flex justify-center" style={{ background: "rgba(20,18,24,0.5)" }} onClick={onClose}>
      <div className="w-full max-w-md flex flex-col" style={{ background: "#FAF8F5", marginTop: "10vh", borderRadius: "20px 20px 0 0", maxHeight: "80vh" }} onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between px-4 py-4" style={{ borderBottom: "1px solid #ECE8E1" }}>
          <div className="flex items-center gap-2">
            <Trophy size={18} color={PRIMARY} />
            <span style={{ fontFamily: "Prompt, sans-serif", fontWeight: 700, fontSize: 16, color: "#1A1A1E" }}>คะแนนเมมเบอร์ทั้งหมด</span>
          </div>
          <button onClick={onClose} style={{ color: "#1A1A1E" }}><X size={22} /></button>
        </div>
        <div className="overflow-y-auto px-4 py-3" style={{ flex: 1 }}>
          {ranked.length === 0 && <p className="text-center text-sm py-10" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>ยังไม่มีข้อมูล</p>}
          {ranked.map(({ member, score }, i) => {
            const color = unitColor(member.unit);
            const medal = i < 3 ? medalStyle[i] : null;
            return (
              <div key={member.id} className="flex items-center gap-3 py-2.5 px-2.5 rounded-xl mb-1" style={{ background: medal ? medal.bg : "transparent" }}>
                <div className="flex items-center justify-center flex-shrink-0" style={{ width: 22 }}>
                  <span className="text-xs font-semibold" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>{i + 1}</span>
                </div>
                <Avatar user={member} size={38} ring />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-1">
                    <span className="text-sm truncate" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>{member.displayName}</span>
                    <BadgeCheck size={12} color="#fff" fill="#3B9EFF" className="flex-shrink-0" />
                  </div>
                  <span className="text-[10px]" style={{ color, fontFamily: "Prompt, sans-serif" }}>{unitLabel(member.unit)}{member.gen ? ` · ${member.gen}` : ""}</span>
                </div>
                <span className="text-sm font-semibold flex-shrink-0" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>{score.toLocaleString()}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

const medalStyle = [
  { bg: "#FDF3DC" },
  { bg: "#F3F4F6" },
  { bg: "#FBEEE3" },
];

function Top5Bars({ onViewAll }) {
  const ranked = useMemberScores().slice(0, 5);
  if (ranked.length === 0) return null;
  const maxScore = Math.max(1, ranked[0].score);
  const maxBarHeight = 92;
  const rankColors = ["#F3C765", "#C9CDD6", "#E3A876", "#B9B6C6", "#B9B6C6"];
  return (
    <div className="px-4 pt-6">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Trophy size={17} color={PRIMARY} />
          <h2 style={{ fontFamily: "Prompt, sans-serif", fontWeight: 600, fontSize: 16, color: "#1A1A1E" }}>Top 5 ประจำสัปดาห์</h2>
        </div>
        <button onClick={onViewAll} className="flex items-center gap-0.5 text-xs font-semibold" style={{ color: PRIMARY, fontFamily: "Prompt, sans-serif" }}>
          View All <ChevronRight size={14} />
        </button>
      </div>
      <div className="flex items-end justify-between gap-2">
        {ranked.map(({ member, score }, i) => {
          const color = unitColor(member.unit);
          const barHeight = Math.max(24, (score / maxScore) * maxBarHeight);
          return (
            <div key={member.id} className="flex-1 flex flex-col items-center">
              <div className="relative mb-1.5" style={{ marginBottom: -14 }}>
                <Avatar user={member} size={44} ring />
                <span className="absolute -top-1 -right-1 flex items-center justify-center rounded-full text-[9px] font-bold" style={{ width: 16, height: 16, background: rankColors[i], color: "#1A1A1E" }}>{i + 1}</span>
              </div>
              <div className="w-full rounded-t-lg" style={{ height: barHeight, background: `linear-gradient(180deg, ${color}, ${color}55)`, marginTop: 14 }} />
              <p className="text-[11px] font-medium mt-2 text-center leading-tight" style={{ color: "#1A1A1E", fontFamily: "Prompt, sans-serif" }}>{member.displayName.split(" ")[0]}</p>
              <p className="text-[10px] text-center" style={{ color: "#A9A6B4", fontFamily: "Prompt, sans-serif" }}>{fmt(score)}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function HomeView() {
  const [scoresOpen, setScoresOpen] = useState(false);
  return (
    <div style={{ paddingBottom: 12 }}>
      <ChampHero />
      <Top5Bars onViewAll={() => setScoresOpen(true)} />
      <AllScoresModal open={scoresOpen} onClose={() => setScoresOpen(false)} />
    </div>
  );
}

